oxy_webhelp_navlinks = {"mysql_obj_level_pause_protection-d30753e31529":{"topics":[{"title":"Pausing protection for MySQL instances","shortdesc":"<p class=\"shortdesc\">You can pause protection for individual MySQL instances to temporarily suspend         scheduled backup operations during maintenance windows or troubleshooting without affecting         other instances in the environment.<\/p>","href":"mysql\/mysql_pausing_protection.html","attributes":{"data-id":"mysql_pausing_protection"},"menu":{"hasChildren":false},"tocID":"mysql_pausing_protection-d30753e31540","topics":[]},{"title":"Resuming protection for MySQL instances","shortdesc":"<p class=\"shortdesc\">You can resume protection for MySQL instances that were previously paused to restore         scheduled backup operations according to the assigned SLA Domain policy.<\/p>","href":"mysql\/mysql_resuming_protection.html","attributes":{"data-id":"mysql_resuming_protection"},"menu":{"hasChildren":false},"tocID":"mysql_resuming_protection-d30753e31551","topics":[]}]}};